refsection.programlisting:

load(GROCERDIR+'\data\us_modinf.dat')
bounds('1960q3','2008q2')
// recover the endogenous, compulsory and optional arguments matrices from selected variables in database us_modinf.dat
 [mats,names]=explon(list('100*lagts(-1,delts(log(GDPDEFL)))',['const';'100*delts(log(GDPDEFL))';'100*lagts(delts(log(GDPDEFL)))'],...
['UNRATE';'100*delts(log(PCECC96))';'100*delts(log(PRFI))';'100*delts(log(GDPC96))';'log(HOUST)']),...
['endogenous' 'fixed exogenous' 'variable exogenous'],[],%t,%t);
y=mats(1);
zf=mats(2);
zv=mats(3);
// run a DMA1 estimation with matrices y, zf,zv, maximum number of optional argument set to 5 (i.e the number
// of optional variables), forgetting factor for past observations in the calculation of the time-varying coefficients set to 0.99,
// forgetting factor of past performance set to 0.99 and default values for other parameters,
// prior values set to 0 for all coefficients, prior variances set to 100 for all coefficients,
// and big volume information saved into files gdpdefl1.dat, gdpdefl2.dat,... in folder 'c:/mydma'

resdma=DMA1(y,zf,zv,0.99,0.99,5,zeros(1,8),100*ones(1,8),'c:/mydma/gdpdefl')
